-- Nuevas columnas en consorcios: servicios centrales Art. 6 CCT 589/10
ALTER TABLE app.consorcios
  ADD COLUMN IF NOT EXISTS tiene_ascensor boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_agua_caliente_central boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_calefaccion_central boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_aire_acondicionado_central boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_grupo_electrogeno boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_seguridad_centralizada boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_compactador boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_montacargas boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS tiene_otros_servicios_centrales boolean NOT NULL DEFAULT false;

-- Nueva tabla: conceptos adicionales por período y consorcio
CREATE TABLE IF NOT EXISTS app.conceptos_adicionales_periodo (
  id           SERIAL PRIMARY KEY,
  periodo      DATE NOT NULL,
  consorcio_cuit VARCHAR NOT NULL REFERENCES app.consorcios(cuit) ON DELETE CASCADE,
  concepto     VARCHAR NOT NULL,
  tipo         VARCHAR NOT NULL CHECK (tipo IN ('haber', 'descuento')),
  importe      NUMERIC NOT NULL,
  es_porcentaje BOOLEAN NOT NULL DEFAULT false,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (periodo, consorcio_cuit, concepto)
);

